import sys
mod = 10**9 + 7

def I():
    return int(input().strip())

def LI():
    return list(map(int, input().strip().split()))

def nCr(n,r):
    if r > n or r < 0:
        return 0
    numerator = 1
    denominator = 1
    for i in range(r):
        numerator = (numerator * (n - i)) % mod
        denominator = (denominator * (i + 1)) % mod
    return (numerator * pow(denominator, mod-2, mod)) % mod

# Read input properly  
