def sum_paths(r, c):
    # This gives sum_{i=0}^r sum_{j=0}^c C(i+j,i) 
    # By hockey stick identity it equals C(r+c+1,r+1) - 1
    if r < 0 or c < 0:
        return 0
    return (nCr(r+c+1, r+1) - 1) % mod

