def count_divisors_of_factorial(n):
    # Get prime factorization of n!
    prime_powers = {}

    # Sieve of Eratosthenes to find all primes up to n
    is_prime = [True] * (n + 1)
    is_prime[0] = is_prime[1] = False

    for i in range(2, n + 1):
        if is_prime[i]:
            # Count powers of i in n!
            power = 0
            temp = n
            while temp > 0:
                temp //= i
                power += temp
            prime_powers[i] = power
            # Mark multiples of i as not prime
            for j in range(i * i, n + 1, i):
                is_prime[j] = False

    return prime_powers

def count_shichigo_numbers(n):
    # Get factorization of n!
    prime_powers = count_divisors_of_factorial(n)

    # For a number to have exactly 75 divisors, 
    # the product of (exponents + 1) must equal 75
    # The ways to write 75 as a product of integers > 1:
    # 75 = 75
    # 75 = 25 * 3  
    # 75 = 15 * 5
    # 75 = 5 * 5 * 3

    count = 0
    primes_list = list(prime_powers.keys())

    # Case 1: 75 = 75 (one prime to power 74)
    for prime, power in prime_powers.items():
        if power >= 74:
            count += 1

    # Case 2: 75 = 25 * 3 (one prime to power 24, another to power 2)  
    for i in range(len(primes_list)):
        p1 = primes_list[i]
        if prime_powers[p1] >= 24:
            for j in range(len(primes_list)):
                if i == j:
                    continue
                p2 = primes_list[j]
                if prime_powers[p2] >= 2:
                    count += 1

    # Case 3: 75 = 15 * 5 (one prime to power 14, another to power 4)
    for i in range(len(primes_list)):
        p1 = primes_list[i]
        if prime_powers[p1] >= 14:
            for j in range(len(primes_list)):
                if i == j:
                    continue
                p2 = primes_list[j]
                if prime_powers[p2] >= 4:
                    count += 1

    # Case 4: 75 = 5 * 5 * 3 (one prime to power 4, another to power 4, third to power 2)
    for i in range(len(primes_list)):
        p1 = primes_list[i]
        if prime_powers[p1] >= 4:
            for j in range(i+1, len(primes_list)):
                p2 = primes_list[j]
                if prime_powers[p2] >= 4:
                    for k in range(j+1, len(primes_list)):
                        p3 = primes_list[k]
                        if prime_powers[p3] >= 2:
                            count += 1

    return count

N = int(input())
print(count_shichigo_numbers(N))
